package com.careeros.search.infrastructure;import com.careeros.search.domain.*;import org.springframework.data.domain.*;import org.springframework.data.jpa.repository.*;import org.springframework.stereotype.Repository;import java.util.*;interface SpringDataSavedSearchRepository extends JpaRepository<SavedSearch,UUID>{}@Repository class SavedSearchRepositoryAdapter implements SavedSearchRepository{private final SpringDataSavedSearchRepository r;SavedSearchRepositoryAdapter(SpringDataSavedSearchRepository r){this.r=r;}public SavedSearch save(SavedSearch s){return r.save(s);}public Optional<SavedSearch>findById(UUID id){return r.findById(id);}public Page<SavedSearch>findAll(Pageable p){return r.findAll(p);}public void deleteById(UUID id){r.deleteById(id);}}
